// src/pages/SemesterSelection.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSemestersForYear } from '../services/api';
import { getCourseById } from '../config/config';
import './SemesterSelection.css';

const SemesterSelection = () => {
  const { courseId, yearId } = useParams();
  const navigate = useNavigate();
  const [semesters, setSemesters] = useState([]);
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSemestersData();
  }, [courseId, yearId]);

  const calculateSemesterNumbers = (year, courseType) => {
    const yearNum = parseInt(year);
    
    // Calculate base semester based on course type and year
    let baseSem = 0;
    
    if (courseType === 'btech') {
      // B.Tech: 4 years, 8 semesters
      baseSem = (yearNum - 1) * 2; // Year 1: 0, Year 2: 2, Year 3: 4, Year 4: 6
    } else if (courseType === 'bca' || courseType === 'bba') {
      // BCA/BBA: 3 years, 6 semesters
      baseSem = (yearNum - 1) * 2; // Year 1: 0, Year 2: 2, Year 3: 4
    } else if (courseType === 'mba' || courseType === 'mca') {
      // MBA/MCA: 2 years, 4 semesters
      baseSem = (yearNum - 1) * 2; // Year 1: 0, Year 2: 2
    }
    
    const semesterCount = 2; // Always 2 semesters per year
    const semesters = [];
    
    for (let i = 1; i <= semesterCount; i++) {
      const semesterNumber = baseSem + i;
      semesters.push({
        semesterNumber,
        name: `Semester ${semesterNumber}`,
        displayNumber: semesterNumber
      });
    }
    
    return semesters;
  };

  const fetchSemestersData = async () => {
    try {
      // Get course info
      const courseData = getCourseById(courseId);
      setCourse(courseData);

      if (!courseData) {
        setLoading(false);
        return;
      }

      // Check if selected year is valid for this course
      const yearNum = parseInt(yearId);
      if (yearNum > courseData.years) {
        console.warn(`Year ${yearNum} not available for ${courseData.name}`);
        setLoading(false);
        return;
      }

      let semestersData;

      try {
        // API call
        semestersData = await getSemestersForYear(courseId, yearNum);
        
        // Ensure we only take maximum 2 semesters from API response
        if (semestersData.length > 2) {
          semestersData = semestersData.slice(0, 2);
        }
        
        // Update semester numbers based on year and course
        const semesterNumbers = calculateSemesterNumbers(yearId, courseId);
        
        semestersData = semestersData.map((sem, index) => ({
          ...sem,
          id: semesterNumbers[index]?.semesterNumber || index + 1,
          name: semesterNumbers[index]?.name || `Semester ${index + 1}`,
          displayNumber: semesterNumbers[index]?.displayNumber || index + 1
        }));
        
      } catch (apiError) {
        console.log('API failed, using fallback data');

        // Fallback semesters with correct numbering
        const semesterNumbers = calculateSemesterNumbers(yearId, courseId);
        
        semestersData = semesterNumbers.map((sem, index) => ({
          id: sem.semesterNumber,
          name: sem.name,
          displayNumber: sem.displayNumber,
          subjects: courseId === 'mba' || courseId === 'mca' ? 5 : 6, // Masters have fewer subjects
          credits: courseId === 'mba' || courseId === 'mca' ? 20 : 24
        }));
      }

      // Final check: Ensure exactly 2 semesters
      if (semestersData.length !== 2) {
        console.warn(`Expected 2 semesters for year ${yearId}, but got ${semestersData.length}. Using fallback.`);
        const semesterNumbers = calculateSemesterNumbers(yearId, courseId);
        
        semestersData = semesterNumbers.map((sem, index) => ({
          id: sem.semesterNumber,
          name: sem.name,
          displayNumber: sem.displayNumber,
          subjects: courseId === 'mba' || courseId === 'mca' ? 5 : 6,
          credits: courseId === 'mba' || courseId === 'mca' ? 20 : 24
        }));
      }

      setSemesters(semestersData);
    } catch (error) {
      console.error('Error fetching semesters:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSemesterClick = (semesterId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semesterId}`);
  };

  const handleBack = () => {
    navigate(`/course/${courseId}`);
  };

  const getSemesterRange = () => {
    if (!course) return '';
    
    const yearNum = parseInt(yearId);
    const startSem = (yearNum - 1) * 2 + 1;
    const endSem = yearNum * 2;
    
    // Check if end semester exceeds total semesters for the course
    if (endSem > course.totalSemesters) {
      return `Semester ${startSem} to ${course.totalSemesters}`;
    }
    
    return `Semester ${startSem} to ${endSem}`;
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading semesters...</p>
      </div>
    );
  }

  if (!course) {
    return (
      <div className="error-container">
        <h3>Course not found!</h3>
        <button onClick={handleBack} className="back-button">
          ← Back to Courses
        </button>
      </div>
    );
  }

  // Check if year is valid for this course
  const yearNum = parseInt(yearId);
  if (yearNum > course.years) {
    return (
      <div className="error-container">
        <h3>Invalid Year for {course.name}</h3>
        <p>This course has only {course.years} years.</p>
        <button onClick={handleBack} className="back-button">
          ← Back to Years
        </button>
      </div>
    );
  }

  return (
    <div className="semester-container">
      {/* Header */}
      <div className="semester-header">
        <button onClick={handleBack} className="back-button">
          ← Back to Years
        </button>
        <div className="page-header">
          <h1 className="title">
            <span className="course-icon">{course.icon}</span>
            {course.name} - Year {yearId}
          </h1>
          <p className="subtitle">
            {course.description} • Select your semester
          </p>
        </div>
      </div>

      {/* Course Info Banner */}
      <div className="course-info-banner">
        <div className="course-info-item">
          <span className="info-icon">📅</span>
          <div>
            <p className="info-label">Total Years</p>
            <p className="info-value">{course.years}</p>
          </div>
        </div>
        <div className="course-info-item">
          <span className="info-icon">📚</span>
          <div>
            <p className="info-label">Total Semesters</p>
            <p className="info-value">{course.totalSemesters}</p>
          </div>
        </div>
        <div className="course-info-item">
          <span className="info-icon">🎯</span>
          <div>
            <p className="info-label">Current Year</p>
            <p className="info-value">{yearId} of {course.years}</p>
          </div>
        </div>
      </div>

      {/* Semesters Grid - Always 2 semesters */}
      <div className="semesters-grid">
        {semesters.map((semester) => (
          <div
            key={semester.id}
            className="semester-card"
            onClick={() => handleSemesterClick(semester.id)}
          >
            <div className="semester-header">
              <div className="semester-number">{semester.displayNumber}</div>
              <div>
                <h3 className="semester-name">{semester.name}</h3>
                <p className="semester-status">
                  {semester.displayNumber <= course.totalSemesters ? 'Active' : 'Not Available'}
                </p>
              </div>
            </div>

            <div className="semester-info">
              <div className="info-item">
                <span className="info-label">Subjects:</span>
                <span className="info-value">{semester.subjects}</span>
              </div>
              <div className="info-item">
                <span className="info-label">Credits:</span>
                <span className="info-value">{semester.credits}</span>
              </div>
              <div className="info-item">
                <span className="info-label">Type:</span>
                <span className="info-value">
                  {courseId === 'mba' || courseId === 'mca' ? 'Master\'s' : 'Bachelor\'s'}
                </span>
              </div>
            </div>

            <div className="materials-list">
              <span className="material-badge">Syllabus</span>
              <span className="material-badge">Notes</span>
              <span className="material-badge">PYQs</span>
              {courseId === 'btech' || courseId === 'bca' || courseId === 'mca' ? (
                <span className="material-badge">Lab Files</span>
              ) : (
                <span className="material-badge">Case Studies</span>
              )}
            </div>

            <button 
              className="view-button"
              disabled={semester.displayNumber > course.totalSemesters}
            >
              {semester.displayNumber <= course.totalSemesters 
                ? 'View Subjects →' 
                : 'Not Available'}
            </button>
          </div>
        ))}
      </div>

      {/* Year Info */}
      <div className="year-info">
        <h3>📚 Year {yearId} Information</h3>
        <p>
          Semesters: {getSemesterRange()} • 
          Total Credits: {semesters.reduce((sum, sem) => sum + sem.credits, 0)} • 
          Total Subjects: {semesters.reduce((sum, sem) => sum + sem.subjects, 0)}
        </p>
        <div className="semester-range">
          <p><strong>Course Type:</strong> 
            {courseId === 'mba' || courseId === 'mca' ? ' Master\'s Program' : ' Bachelor\'s Program'}
          </p>
          <p><strong>Duration:</strong> {course.years} Years ({course.totalSemesters} Semesters)</p>
        </div>
      </div>
    </div>
  );
};

export default SemesterSelection;
